15	#ifndef STB_IMAGE_WRITE_IMPLEMENTATION
16	#define STB_IMAGE_WRITE_IMPLEMENTATION
17	#include "stb_image_write.h"
18	#endif
19	
20	#if defined(EEPIMG_ASCII_IMPLEMENTATION)
21	#include "eep_ascii.h"
22	#endif
23	
24	using namespace  std;
25	
26	////////////////////////////////////////////////////
27	// version: v0.2.6
28	/*
29	v0.2.6: update eepimg_load_image, add RGBA/BGRA.
30	v0.2.5: open function: eepimg_make_image_bytes; eepimg_copy_image;
31	v0.2.4: add eepimg_crop_resize()
32	v0.2.3: fixed bug(load image and crop/resize)
33	*/
34	
35	/////////// internal functions /////////////////////
36	static void *xcalloc(size_t nmemb, size_t size);
37	static image_bytes eepimg_make_empty_image_bytes(int w, int h, int c);
38	image_bytes eepimg_make_image_bytes(int w, int h, int c);
39	image_bytes eepimg_copy_image(image_bytes p);
40	static void eepimg_rgbgr_image(image_bytes im);
41	////////////////////////////////////////////////////
42	
43	/*
44	eepimg pixel default format:
45	    rgbrgbrgb....rgb...
46	*/
47	
48	image_bytes eepimg_load_image(char *filename, int pixel_order)
49	{
50	    int w, h, c;
51	    
52	    int stbi = 0;
53	    if (pixel_order == EEPIMG_PIXEL_GRAY) stbi = STBI_grey;
54	    unsigned char *data = stbi_load(filename, &w, &h, &c, stbi);
55	    if (!data) 
56	    {
57	        char shrinked_filename[1024];
58	        if (strlen(filename) >= 1024) sprintf(shrinked_filename, "name is too long");
59	        else sprintf(shrinked_filename, "%s", filename);
60	        fprintf(stderr, "Cannot load image \"%s\"\nSTB Reason: %s\n", shrinked_filename, stbi_failure_reason());
61	        return eepimg_make_empty_image_bytes(0, 0, 0);
62	    }
63	    
64	    image_bytes im;
65	    //printf("chw=%d,%d,%d, pixel=%d\n", c,h,w, pixel_order);
66	    
67	    if (pixel_order == EEPIMG_PIXEL_GRAY) c = 1;
68	    
69	    if (pixel_order == EEPIMG_PIXEL_DFT)
70	    {
71	        // default is gray/rgb/rgba
72	        im = eepimg_make_image_bytes(w, h, c);    
73	        memcpy(im.data, data, w*h*c);
74	    }
75	    else if (c == 1 && (pixel_order == EEPIMG_PIXEL_GRAY))
76	    {
77	        im = eepimg_make_image_bytes(w, h, 1);
78	        memcpy(im.data, data, w*h*1);
79	    }
80	    else if (c == 1 && ( (pixel_order == EEPIMG_PIXEL_RGB) || (pixel_order == EEPIMG_PIXEL_BGR) ) )
81	    {
82	        // gray to rgb 
83	        im = eepimg_make_image_bytes(w, h, 3);
84	        unsigned char* psrc = data;
85	        unsigned char* pdst = im.data;
86	        for (int i = 0; i < w*h; i++)
87	        {
88	            *pdst++ = *psrc;
89	            *pdst++ = *psrc;
90	            *pdst++ = *psrc++;
91	        }
92	    }
93	    else if (c == 3)   // rgb
94	    {
95	        // default is rgb
96	        
97	        if (pixel_order == EEPIMG_PIXEL_BGR)
98	        {
99	            im = eepimg_make_image_bytes(w, h, c); 
100	            memcpy(im.data, data, w*h*c);
101	            eepimg_rgbgr_image(im);
102	        }
103	        else if (pixel_order == EEPIMG_PIXEL_BGRA)
104	        {
105	            im = eepimg_make_image_bytes(w, h, 4); 
106	            unsigned char* psrc = data;
107	            unsigned char* pdst = im.data;
108	            for (int i = 0; i < w*h; i++)
109	            {
110	                pdst[2] = psrc[0];
111	                pdst[1] = psrc[1];
112	                pdst[0] = psrc[2];
113	                pdst[3] = 255.0;
114	                psrc += 3;
115	                pdst += 4;
116	            }
117	        }
118	        else if (pixel_order == EEPIMG_PIXEL_RGBA)
119	        {
120	            im = eepimg_make_image_bytes(w, h, 4); 
121	            unsigned char* psrc = data;
122	            unsigned char* pdst = im.data;
123	            for (int i = 0; i < w*h; i++)
124	            {
125	                pdst[0] = psrc[0];
126	                pdst[1] = psrc[1];
127	                pdst[2] = psrc[2];
128	                pdst[3] = 255.0;
129	                psrc += 3;
130	                pdst += 4;
131	            }
132	        }
133	        else    // default, rgb
134	        {
135	            im = eepimg_make_image_bytes(w, h, c); 
136	            memcpy(im.data, data, w*h*c);
137	        }
138	    }
139	    else if (c == 4)    // rgba
140	    {
141	        if (pixel_order == EEPIMG_PIXEL_RGB)
142	        {
143	            im = eepimg_make_image_bytes(w, h, 3);
144	            unsigned char* psrc = data;
145	            unsigned char* pdst = im.data;
146	            for (int i = 0; i < w*h; i++)
147	            {
148	                float alpha = psrc[3] / 255.0;
149	                pdst[0] = (1.0 - alpha) * 255 + alpha * (psrc[0]);
150	                pdst[1] = (1.0 - alpha) * 255 + alpha * (psrc[1]);
151	                pdst[2] = (1.0 - alpha) * 255 + alpha * (psrc[2]);
152	                psrc += 4;            
153	                pdst += 3;
154	            }
155	        }
156	        else if (pixel_order == EEPIMG_PIXEL_BGR)
157	        {
158	            im = eepimg_make_image_bytes(w, h, 3);
159	            unsigned char* psrc = data;
160	            unsigned char* pdst = im.data;
161	            for (int i = 0; i < w*h; i++)
162	            {
163	                float alpha = psrc[3] / 255.0;
164	                pdst[2] = (1.0 - alpha) * 255 + alpha * (psrc[0]);
165	                pdst[1] = (1.0 - alpha) * 255 + alpha * (psrc[1]);
166	                pdst[0] = (1.0 - alpha) * 255 + alpha * (psrc[2]);
167	                psrc += 4;
168	                pdst += 3;
169	            }
170	        }
171	        else if (pixel_order == EEPIMG_PIXEL_BGRA)
172	        {
173	            im = eepimg_make_image_bytes(w, h, 4);
174	            unsigned char* psrc = data;
175	            unsigned char* pdst = im.data;
176	            for (int i = 0; i < w*h; i++)
177	            {
178	                pdst[2] = psrc[0];
179	                pdst[1] = psrc[1];
180	                pdst[0] = psrc[2];
181	                pdst[3] = psrc[3];
182	                psrc += 4;            
183	                pdst += 4;
184	            }
185	        }
186	        else 
187	        {
188	            im = eepimg_make_image_bytes(w, h, 4);
189	            memcpy(im.data, data, w*h*4);
190	        }
191	    }
192	    else 
193	    {
194	        printf("Can't get stb image data.\n");
195	        return eepimg_make_empty_image_bytes(0, 0, 0);
196	    }
197	    
198	    //printf("read ok, im chw=%d,%d,%d\n", im.c, im.h, im.w);
199	    free(data);
200	    return im;
201	}
202	
203	image_bytes eepimg_load_image(char *filename, int pixel_order, int layout)
204	{
205	    image_bytes im = eepimg_load_image(filename, pixel_order);
206	    if (layout == EEPIMG_LAYOUT_HWC) return im;
207	    else if (layout == EEPIMG_LAYOUT_CHW)
208	    {
209	        image_bytes chw;
210	        chw = eepimg_make_image_bytes(im.w, im.h, im.c);
211	        chw.layout = EEPIMG_LAYOUT_CHW;
212	        
213	        for (int c = 0; c < im.c; c++)
214	        {
215	            unsigned char* pdst = (unsigned char*)chw.data;
216	            pdst += (c * im.h * im.w);
217	            unsigned char* psrc = (unsigned char*)im.data;
218	            psrc += c;
219	            for (int i = 0; i < im.h * im.w; i++)
220	            {
221	                *pdst++ = *psrc;
222	                psrc += im.c;
223	            }
224	        }
225	        
226	        return chw;
227	    }
228	    else 
229	    {
230	        printf("Not supported layout: %d. (supported layout: 0-hwc; 1-chw.)\n", layout);
231	        return eepimg_make_empty_image_bytes(0, 0, 0);
232	    }
233	}
234	
235	image_bytes eepimg_load_image(char *filename, int pixel_order, int resize_w, int resize_h, float crop_scale)
236	{
237	    if (resize_w == 0 || resize_h == 0) return eepimg_make_empty_image_bytes(0, 0, 0);
238	    
239	    image_bytes im = eepimg_load_image(filename, pixel_order);
240	    if (eepimg_empty(im) == true) return im;
241	    
242	    if (crop_scale == 0.0) crop_scale = 1.0;
243	    if (crop_scale != 1.0)
244	    {
245	        int src_h = im.h;
246	        int src_w = im.w;
247	        int short_edge = min(src_h, src_w);
248	        short_edge *= crop_scale;
249	        int yy = (src_h - short_edge) / 2;
250	        int xx = (src_w - short_edge) / 2;
251	        image_bytes im_crop = eepimg_crop(im, xx, yy, short_edge, short_edge);
252	        eepimg_free(im);
253	        
254	        if (im_crop.w == resize_w && im_crop.h == resize_h) return im_crop;
255	        else
256	        {
257	            image_bytes img_resized = eepimg_resize(im_crop, resize_w, resize_h);
258	            eepimg_free(im_crop);
259	            return img_resized;
260	        }
261	    }
262	    else
263	    {
264	        if (im.w == resize_w && im.h == resize_h) return im;
265	        else
266	        {
267	            image_bytes img_resized = eepimg_resize(im, resize_w, resize_h);
268	            eepimg_free(im);
269	            return img_resized;
270	        }
271	    }
272	    
273	    return im;
274	}
275	
276	image_bytes eepimg_crop_resize(image_bytes im, int resize_w, int resize_h, float crop_scale)
277	{
278	    if (resize_w == 0 || resize_h == 0) return eepimg_make_empty_image_bytes(0, 0, 0);
279	    if (eepimg_empty(im) == true) return eepimg_copy_image(im);
280	    
281	    if (crop_scale == 0.0) crop_scale = 1.0;
282	    if (crop_scale != 1.0)
283	    {
284	        int src_h = im.h;
285	        int src_w = im.w;
286	        int short_edge = min(src_h, src_w);
287	        short_edge *= crop_scale;
288	        int yy = (src_h - short_edge) / 2;
289	        int xx = (src_w - short_edge) / 2;
290	        image_bytes im_crop = eepimg_crop(im, xx, yy, short_edge, short_edge);
291	        
292	        if (im_crop.w == resize_w && im_crop.h == resize_h) return im_crop;
293	        else
294	        {
295	            image_bytes img_resized = eepimg_resize(im_crop, resize_w, resize_h);
296	            eepimg_free(im_crop);
297	            return img_resized;
298	        }
299	    }
300	    else
301	    {
302	        if (im.w == resize_w && im.h == resize_h) 
303	        {
304	            return eepimg_copy_image(im);
305	        }
306	        else
307	        {
308	            image_bytes img_resized = eepimg_resize(im, resize_w, resize_h);
309	            return img_resized;
310	        }
311	    }
312	    
313	    return eepimg_copy_image(im);
314	}
315	
316	void eepimg_from_buffer(image_bytes* im, unsigned char* data, int w, int h, int c)
317	{
318	    im->w = w;
319	    im->h = h;
320	    im->c = c;
321	    if (im->data != NULL) free(im->data);
322	    im->data = (unsigned char*)xcalloc(h * w * c, sizeof(unsigned char));
323	    memcpy(im->data, data, h*w*c);
324	}
325	
326	void eepimg_free(image_bytes im)
327	{
328	    if(im.data)
329	    {
330	        free(im.data);
331	        im.data = NULL;
332	    }
333	}
334	
335	bool eepimg_empty(image_bytes im)
336	{
337	    if (im.w == 0 || im.h == 0 || im.c == 0) return true;
338	    if (im.data == NULL) return true;
339	    else return false;
340	}
341	
342	image_bytes eepimg_resize(image_bytes im, int w, int h)
343	{
344	    if (im.w == w && im.h == h) return eepimg_copy_image(im);
345	    
346	    image_bytes resized = eepimg_make_image_bytes(w, h, im.c);
347	    
348	    stbir_resize_uint8(im.data, im.w, im.h, 0, resized.data, w, h, 0, im.c);
349	    
350	    return resized;
351	}
352	
353	/*
354	crop image from pixel(x0,y0), width is w, height is h.
355	pixel format is: 
356	    rgb:  rgbrgbrgb.....
357	    bgr:  bgrbgrbgr.....
358	    gray: ggggggggg.....
359	*/
360	image_bytes eepimg_crop(image_bytes im, int x0, int y0, int w, int h)
361	{
362	    if (x0==0 && y0==0 && im.w == w && im.h == h) 
363	    {
364	        return eepimg_copy_image(im);
365	    }
366	
367	    if (x0 >= im.w) return eepimg_make_image_bytes(w,h,im.c);
368	    if ( (x0 + w) > im.w ) w = im.w - x0;
369	    if (y0 >= im.h) return eepimg_make_image_bytes(w,h,im.c);
370	    if ( (y0 + h) > im.h ) h = im.h - y0;
371	
372	    image_bytes crop = eepimg_make_image_bytes(w, h, im.c);
373	    unsigned char* pdst = crop.data;
374	    
375	    int row_bytes = im.c * im.w;
376	    //int curr_h = 0;
377	    int copy_len = w * im.c;
378	    unsigned char* psrc = im.data + row_bytes*y0 + x0*im.c;
379	    
380	    for (int i = 0; i < h; i++)
381	    {
382	        memcpy(pdst, psrc, copy_len);
383	        pdst += copy_len;
384	        psrc += row_bytes;
385	    }
386	
387	    return crop;
388	}
389	
390	int eepimg_save(const char* filename, image_bytes im, bool swapRB)
391	{
392	    int ret = -1;
393	    const char* ptr = strrchr(filename, '.');
394	    if (ptr == NULL) return -1;
395	    
396	    image_bytes sm;
397	    if (swapRB) 
398	    {
399	        sm = eepimg_copy_image(im);
400	        eepimg_rgbgr_image(sm);
401	    }
402	    else sm = im;
403	            
404	    if (strcasecmp(ptr, ".bmp") == 0)
405	    {
406	        ret = stbi_write_bmp(filename, sm.w, sm.h, sm.c, sm.data);
407	    }
408	    else if (strcasecmp(ptr, ".png") == 0)
409	    {
410	        ret = stbi_write_png(filename, sm.w, sm.h, sm.c, sm.data, 0);
411	    }
412	    else if (strcasecmp(ptr, ".jpg") == 0)
413	    {
414	        ret = stbi_write_jpg(filename, sm.w, sm.h, sm.c, sm.data, 85);
415	    }
416	    else ret = -1;
417	    
418	    if (swapRB) eepimg_free(sm);
419	    return ret;
420	}
421	
422	image_bytes eepimg_draw_box(image_bytes img, int x1, int y1, int x2, int y2, unsigned char b, unsigned char g, unsigned char r, unsigned char linewidth)
423	{
424	    image_bytes im = eepimg_copy_image(img);
425	    
426	    int i;
427	    if(x1 < 0) x1 = 0;
428	    if(x1 >= im.w) x1 = im.w-1;
429	    if(x2 < 0) x2 = 0;
430	    if(x2 >= im.w) x2 = im.w-1;
431	    if (x1 > x2) { i = x2; x2 = x1; x1 = i; }
432	
433	    if(y1 < 0) y1 = 0;
434	    if(y1 >= im.h) y1 = im.h-1;
435	    if(y2 < 0) y2 = 0;
436	    if(y2 >= im.h) y2 = im.h-1;
437	    if (y1 > y2) { i = y2; y2 = y1; y1 = i; }
438	    
439	    if (linewidth < 1) linewidth = 1;
440	    
441	    int row_bytes = im.w * im.c;
442	    unsigned char gray = (b+g+r) / 3;
443	    
444	    unsigned char* ptr;
445	
446	    // - (x1,y1)->(x2,y1)
447	    for (int n = 0; n < linewidth; n++)
448	    {
449	        if (y1+n >= im.h) break;
450	        ptr = im.data + (y1+n) * row_bytes + x1 * im.c;
451	        if (im.c == 3) for(i = x1; i <= x2; ++i) { *ptr++ = b; *ptr++ = g; *ptr++ = r; } 
452	        else if (im.c == 1) for(i = x1; i <= x2; ++i) { *ptr++ = gray; } 
453	    }
454	    
455	    // - (x1,y2)->(x2,y2)
456	    for (int n = 0; n < linewidth; n++)
457	    {
458	        if (y2+n >= im.h) break;
459	        ptr = im.data + (y2+n) * row_bytes + x1 * im.c;
460	        if (im.c == 3) for(i = x1; i <= x2; ++i) { *ptr++ = b; *ptr++ = g; *ptr++ = r; } 
461	        else if (im.c == 1) for(i = x1; i <= x2; ++i) { *ptr++ = gray; } 
462	    }
463	    
464	    // | (x1,y1)->(x1,y2)
465	    for (int n = 0; n < linewidth; n++)
466	    {
467	        if (x1+n > im.w) break;
468	        ptr = im.data + y1 * row_bytes + (x1+n) * im.c;
469	        if (im.c == 3) for(i = y1; i <= y2; ++i) { ptr[0] = b; ptr[1] = g; ptr[2] = r; ptr += row_bytes; } 
470	        else if (im.c == 1) for(i = y1; i <= y2; ++i) { ptr[0] = gray; ptr += row_bytes; } 
471	    }
472	    
473	    // | (x2,y1)->(x2,y2)
474	    y2 += (linewidth-1);
475	    if (y2 >= im.h) y2 = im.h - 1;
476	    for (int n = 0; n < linewidth; n++)
477	    {
478	        if (x2+n > im.w) break;
479	        ptr = im.data + y1 * row_bytes + (x2+n) * im.c;
480	        if (im.c == 3) for(i = y1; i <= y2; ++i) { ptr[0] = b; ptr[1] = g; ptr[2] = r; ptr += row_bytes; } 
481	        else if (im.c == 1) for(i = y1; i <= y2; ++i) { ptr[0] = gray; ptr += row_bytes; } 
482	    }
483	
484	    return im;
485	}
